"use client"

import { useEffect, useState } from "react"
import { Plus, Package, Pencil, Trash } from "lucide-react"
import { Button } from "@/components/ui/button"
import { Badge } from "@/components/ui/badge"
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from "@/components/ui/table"
import {
  Sheet,
  SheetContent,
  SheetDescription,
  SheetHeader,
  SheetTitle,
  SheetTrigger,
} from "@/components/ui/sheet"
import {
  AlertDialog,
  AlertDialogAction,
  AlertDialogCancel,
  AlertDialogContent,
  AlertDialogDescription,
  AlertDialogHeader,
  AlertDialogTitle,
} from "@/components/ui/alert-dialog"
import { Input } from "@/components/ui/input"
import {
  Select,
  SelectContent,
  SelectItem,
  SelectTrigger,
  SelectValue,
} from "@/components/ui/select"
import { Label } from "@/components/ui/label"
import { Skeleton } from "@/components/ui/skeleton"
import { createProduct, updateProduct, deleteProduct } from "@/app/actions/inventory"

interface Product {
  id: string
  name: string
  sku: string
  category: "RAW_MATERIAL" | "FINISHED_GOOD" | "PACKAGING"
  type: "CRINKLE_CUT" | "STEAKHOUSE_CUT" | "NORMAL_CUT"
  current_stock: number
}

export default function InventoryPage() {
  const [products, setProducts] = useState<Product[]>([])
  const [isLoading, setIsLoading] = useState(true)
  const [isSheetOpen, setIsSheetOpen] = useState(false)
  const [isEditSheetOpen, setIsEditSheetOpen] = useState(false)
  const [isDeleteAlertOpen, setIsDeleteAlertOpen] = useState(false)
  const [editingProduct, setEditingProduct] = useState<Product | null>(null)
  const [productToDelete, setProductToDelete] = useState<Product | null>(null)
  const [formData, setFormData] = useState({
    name: "",
    sku: "",
    category: "",
    type: "NORMAL_CUT",
    current_stock: "",
  })
  const [editFormData, setEditFormData] = useState({
    id: "",
    name: "",
    sku: "",
    category: "",
    type: "NORMAL_CUT",
    current_stock: "",
  })
  const [isSubmitting, setIsSubmitting] = useState(false)

  useEffect(() => {
    fetchProducts()
  }, [])

  const fetchProducts = async () => {
    try {
      setIsLoading(true)
      const response = await fetch("/api/inventory")
      if (response.ok) {
        const data = await response.json()
        setProducts(data.products || [])
      }
    } catch (error) {
      console.error("Failed to fetch products:", error)
    } finally {
      setIsLoading(false)
    }
  }

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!formData.name || !formData.sku || !formData.category || !formData.current_stock) {
      alert("Por favor, completa todos los campos")
      return
    }

    try {
      setIsSubmitting(true)
      const result = await createProduct({
        name: formData.name,
        sku: formData.sku,
        category: formData.category as "RAW_MATERIAL" | "FINISHED_GOOD" | "PACKAGING",
        type: formData.type as "CRINKLE_CUT" | "STEAKHOUSE_CUT" | "NORMAL_CUT",
        current_stock: parseInt(formData.current_stock),
      })

      if (result.success) {
        setFormData({ name: "", sku: "", category: "", type: "NORMAL_CUT", current_stock: "" })
        setIsSheetOpen(false)
        fetchProducts()
        alert(result.message)
      } else {
        alert(result.message)
      }
    } catch (error) {
      console.error("Error:", error)
      alert("Error al crear el producto")
    } finally {
      setIsSubmitting(false)
    }
  }

  const openEditSheet = (product: Product) => {
    setEditingProduct(product)
    setEditFormData({
      id: product.id,
      name: product.name,
      sku: product.sku,
      category: product.category,
      type: product.type,
      current_stock: product.current_stock.toString(),
    })
    setIsEditSheetOpen(true)
  }

  const handleEditSubmit = async (e: React.FormEvent) => {
    e.preventDefault()
    if (!editFormData.name || !editFormData.sku || !editFormData.category || !editFormData.current_stock) {
      alert("Por favor, completa todos los campos")
      return
    }

    try {
      setIsSubmitting(true)
      const result = await updateProduct({
        id: editFormData.id,
        name: editFormData.name,
        sku: editFormData.sku,
        category: editFormData.category as "RAW_MATERIAL" | "FINISHED_GOOD" | "PACKAGING",
        type: editFormData.type as "CRINKLE_CUT" | "STEAKHOUSE_CUT" | "NORMAL_CUT",
        current_stock: parseInt(editFormData.current_stock),
      })

      if (result.success) {
        setEditFormData({ id: "", name: "", sku: "", category: "", type: "NORMAL_CUT", current_stock: "" })
        setIsEditSheetOpen(false)
        setEditingProduct(null)
        fetchProducts()
        alert(result.message)
      } else {
        alert(result.message)
      }
    } catch (error) {
      console.error("Error:", error)
      alert("Error al actualizar el producto")
    } finally {
      setIsSubmitting(false)
    }
  }

  const openDeleteAlert = (product: Product) => {
    setProductToDelete(product)
    setIsDeleteAlertOpen(true)
  }

  const handleConfirmDelete = async () => {
    if (!productToDelete) return

    try {
      setIsSubmitting(true)
      const result = await deleteProduct(productToDelete.id)

      if (result.success) {
        setIsDeleteAlertOpen(false)
        setProductToDelete(null)
        fetchProducts()
        alert(result.message)
      } else {
        alert(result.message)
      }
    } catch (error) {
      console.error("Error:", error)
      alert("Error al eliminar el producto")
    } finally {
      setIsSubmitting(false)
    }
  }

  const getCategoryColor = (category: string) => {
    switch (category) {
      case "RAW_MATERIAL":
        return "bg-blue-500/20 text-blue-400 border-blue-500/30"
      case "FINISHED_GOOD":
        return "bg-emerald-500/20 text-emerald-400 border-emerald-500/30"
      case "PACKAGING":
        return "bg-amber-500/20 text-amber-400 border-amber-500/30"
      default:
        return "bg-zinc-500/20 text-zinc-400 border-zinc-500/30"
    }
  }

  const getCategoryLabel = (category: string) => {
    switch (category) {
      case "RAW_MATERIAL":
        return "Materia Prima"
      case "FINISHED_GOOD":
        return "Producto Terminado"
      case "PACKAGING":
        return "Empaque"
      default:
        return category
    }
  }

  const getFriesTypeLabel = (type: string) => {
    switch (type) {
      case "CRINKLE_CUT":
        return "Corte Ondulado"
      case "STEAKHOUSE_CUT":
        return "Corte Steakhouse"
      case "NORMAL_CUT":
        return "Corte Normal"
      default:
        return type
    }
  }

  const getFriesTypeColor = (type: string) => {
    switch (type) {
      case "CRINKLE_CUT":
        return "bg-purple-500/20 text-purple-400 border-purple-500/30"
      case "STEAKHOUSE_CUT":
        return "bg-pink-500/20 text-pink-400 border-pink-500/30"
      case "NORMAL_CUT":
        return "bg-cyan-500/20 text-cyan-400 border-cyan-500/30"
      default:
        return "bg-zinc-500/20 text-zinc-400 border-zinc-500/30"
    }
  }

  return (
    <div className="p-8">
      {/* Header */}
      <div className="flex items-center justify-between mb-8">
        <div>
          <h1 className="text-4xl font-bold text-white mb-2 flex items-center gap-2">
            <Package className="w-8 h-8 text-emerald-400" />
            Gestión de Inventario
          </h1>
          <p className="text-zinc-400">Administra todos los productos y niveles de existencias</p>
        </div>
        <Sheet open={isSheetOpen} onOpenChange={setIsSheetOpen}>
          <SheetTrigger asChild>
            <Button className="bg-emerald-600 hover:bg-emerald-700 text-white">
              <Plus className="w-4 h-4 mr-2" />
              Agregar Producto
            </Button>
          </SheetTrigger>
          <SheetContent className="bg-zinc-900 border-zinc-800">
            <SheetHeader>
              <SheetTitle className="text-white">Agregar Nuevo Producto</SheetTitle>
              <SheetDescription className="text-zinc-400">
                Crea un nuevo producto en tu inventario
              </SheetDescription>
            </SheetHeader>
            <form onSubmit={handleSubmit} className="space-y-6 mt-6">
              <div className="space-y-2">
                <Label htmlFor="name" className="text-zinc-300">
                  Nombre del Producto
                </Label>
                <Input
                  id="name"
                  placeholder="Ej: Papas Fritas"
                  value={formData.name}
                  onChange={(e) => setFormData({ ...formData, name: e.target.value })}
                  className="bg-zinc-800 border-zinc-700 text-white placeholder:text-zinc-500"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="sku" className="text-zinc-300">
                  SKU
                </Label>
                <Input
                  id="sku"
                  placeholder="Ej: POT-001"
                  value={formData.sku}
                  onChange={(e) => setFormData({ ...formData, sku: e.target.value })}
                  className="bg-zinc-800 border-zinc-700 text-white placeholder:text-zinc-500"
                />
              </div>

              <div className="space-y-2">
                <Label htmlFor="category" className="text-zinc-300">
                  Categoría
                </Label>
                <Select value={formData.category} onValueChange={(value) => setFormData({ ...formData, category: value })}>
                  <SelectTrigger className="bg-zinc-800 border-zinc-700 text-white">
                    <SelectValue placeholder="Selecciona una categoría" />
                  </SelectTrigger>
                  <SelectContent className="bg-zinc-800 border-zinc-700">
                    <SelectItem value="RAW_MATERIAL" className="text-white">Materia Prima</SelectItem>
                    <SelectItem value="FINISHED_GOOD" className="text-white">Producto Terminado</SelectItem>
                    <SelectItem value="PACKAGING" className="text-white">Empaque</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="type" className="text-zinc-300">
                  Tipo de Corte
                </Label>
                <Select value={formData.type} onValueChange={(value) => setFormData({ ...formData, type: value })}>
                  <SelectTrigger className="bg-zinc-800 border-zinc-700 text-white">
                    <SelectValue placeholder="Selecciona un tipo de corte" />
                  </SelectTrigger>
                  <SelectContent className="bg-zinc-800 border-zinc-700">
                    <SelectItem value="CRINKLE_CUT" className="text-white">Corte Ondulado</SelectItem>
                    <SelectItem value="STEAKHOUSE_CUT" className="text-white">Corte Steakhouse</SelectItem>
                    <SelectItem value="NORMAL_CUT" className="text-white">Corte Normal</SelectItem>
                  </SelectContent>
                </Select>
              </div>

              <div className="space-y-2">
                <Label htmlFor="stock" className="text-zinc-300">
                  Existencias Iniciales (kg)
                </Label>
                <Input
                  id="stock"
                  type="number"
                  placeholder="0"
                  value={formData.current_stock}
                  onChange={(e) => setFormData({ ...formData, current_stock: e.target.value })}
                  className="bg-zinc-800 border-zinc-700 text-white placeholder:text-zinc-500"
                />
              </div>

              <Button
                type="submit"
                disabled={isSubmitting}
                className="w-full bg-emerald-600 hover:bg-emerald-700 text-white"
              >
                {isSubmitting ? "Guardando..." : "Crear Producto"}
              </Button>
            </form>
          </SheetContent>
        </Sheet>
      </div>

      {/* Edit Product Sheet */}
      <Sheet open={isEditSheetOpen} onOpenChange={setIsEditSheetOpen}>
        <SheetContent className="bg-zinc-900 border-zinc-800">
          <SheetHeader>
            <SheetTitle className="text-white">Editar Producto</SheetTitle>
            <SheetDescription className="text-zinc-400">
              Actualiza los detalles del producto
            </SheetDescription>
          </SheetHeader>
          <form onSubmit={handleEditSubmit} className="space-y-6 mt-6">
            <div className="space-y-2">
              <Label htmlFor="edit-name" className="text-zinc-300">
                Nombre del Producto
              </Label>
              <Input
                id="edit-name"
                placeholder="Ej: Papas Fritas"
                value={editFormData.name}
                onChange={(e) => setEditFormData({ ...editFormData, name: e.target.value })}
                className="bg-zinc-800 border-zinc-700 text-white placeholder:text-zinc-500"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-sku" className="text-zinc-300">
                SKU
              </Label>
              <Input
                id="edit-sku"
                placeholder="Ej: POT-001"
                value={editFormData.sku}
                onChange={(e) => setEditFormData({ ...editFormData, sku: e.target.value })}
                className="bg-zinc-800 border-zinc-700 text-white placeholder:text-zinc-500"
              />
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-category" className="text-zinc-300">
                Categoría
              </Label>
              <Select value={editFormData.category} onValueChange={(value) => setEditFormData({ ...editFormData, category: value })}>
                <SelectTrigger className="bg-zinc-800 border-zinc-700 text-white">
                  <SelectValue placeholder="Selecciona una categoría" />
                </SelectTrigger>
                <SelectContent className="bg-zinc-800 border-zinc-700">
                  <SelectItem value="RAW_MATERIAL" className="text-white">Materia Prima</SelectItem>
                  <SelectItem value="FINISHED_GOOD" className="text-white">Producto Terminado</SelectItem>
                  <SelectItem value="PACKAGING" className="text-white">Empaque</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-type" className="text-zinc-300">
                Tipo de Corte
              </Label>
              <Select value={editFormData.type} onValueChange={(value) => setEditFormData({ ...editFormData, type: value })}>
                <SelectTrigger className="bg-zinc-800 border-zinc-700 text-white">
                  <SelectValue placeholder="Selecciona un tipo de corte" />
                </SelectTrigger>
                <SelectContent className="bg-zinc-800 border-zinc-700">
                  <SelectItem value="CRINKLE_CUT" className="text-white">Corte Ondulado</SelectItem>
                  <SelectItem value="STEAKHOUSE_CUT" className="text-white">Corte Steakhouse</SelectItem>
                  <SelectItem value="NORMAL_CUT" className="text-white">Corte Normal</SelectItem>
                </SelectContent>
              </Select>
            </div>

            <div className="space-y-2">
              <Label htmlFor="edit-stock" className="text-zinc-300">
                Existencias (kg)
              </Label>
              <Input
                id="edit-stock"
                type="number"
                placeholder="0"
                value={editFormData.current_stock}
                onChange={(e) => setEditFormData({ ...editFormData, current_stock: e.target.value })}
                className="bg-zinc-800 border-zinc-700 text-white placeholder:text-zinc-500"
              />
            </div>

            <Button
              type="submit"
              disabled={isSubmitting}
              className="w-full bg-emerald-600 hover:bg-emerald-700 text-white"
            >
              {isSubmitting ? "Guardando..." : "Actualizar Producto"}
            </Button>
          </form>
        </SheetContent>
      </Sheet>

      {/* Products Table */}
      <div className="glass-card">
        <div className="p-6 border-b border-white/10">
          <h2 className="text-xl font-bold text-white">Productos</h2>
        </div>

        {isLoading ? (
          <div className="p-6">
            <div className="space-y-3">
              {[1, 2, 3, 4, 5].map((i) => (
                <Skeleton key={i} className="h-12 w-full bg-zinc-800" />
              ))}
            </div>
          </div>
        ) : products.length === 0 ? (
          <div className="p-12 flex flex-col items-center justify-center">
            <div className="w-16 h-16 glass-card rounded-full flex items-center justify-center mb-4">
              <Package className="w-8 h-8 text-zinc-500" />
            </div>
            <h3 className="text-xl font-bold text-white mb-2">Sin Productos</h3>
            <p className="text-zinc-400 text-center mb-6 max-w-md">
              Tu inventario está vacío. Agrega tu primer producto para comenzar.
            </p>
            <Button className="bg-emerald-600 hover:bg-emerald-700 text-white">
              <Plus className="w-4 h-4 mr-2" />
              Agregar Primer Producto
            </Button>
          </div>
        ) : (
          <div className="overflow-x-auto">
            <Table>
              <TableHeader>
                <TableRow className="border-white/10 hover:bg-transparent">
                  <TableHead className="text-zinc-300">Nombre</TableHead>
                  <TableHead className="text-zinc-300">SKU</TableHead>
                  <TableHead className="text-zinc-300">Categoría</TableHead>
                  <TableHead className="text-zinc-300">Tipo de Corte</TableHead>
                  <TableHead className="text-zinc-300 text-right">Existencias (kg)</TableHead>
                  <TableHead className="text-zinc-300">Acciones</TableHead>
                </TableRow>
              </TableHeader>
              <TableBody>
                {products.map((product) => (
                  <TableRow key={product.id} className="border-white/5 hover:bg-white/5">
                    <TableCell className="text-white font-medium">{product.name}</TableCell>
                    <TableCell className="font-mono text-zinc-300">{product.sku}</TableCell>
                    <TableCell>
                      <Badge variant="outline" className={`${getCategoryColor(product.category)} border`}>
                        {getCategoryLabel(product.category)}
                      </Badge>
                    </TableCell>
                    <TableCell>
                      <Badge variant="outline" className={`${getFriesTypeColor(product.type)} border`}>
                        {getFriesTypeLabel(product.type)}
                      </Badge>
                    </TableCell>
                    <TableCell className="text-right text-emerald-400 font-semibold">
                      {product.current_stock}
                    </TableCell>
                    <TableCell>
                      <div className="flex gap-1">
                        <button
                          onClick={() => openEditSheet(product)}
                          className="p-2 text-zinc-400 hover:text-white hover:bg-zinc-800 rounded transition-colors"
                          title="Editar producto"
                        >
                          <Pencil className="w-4 h-4" />
                        </button>
                        <button
                          onClick={() => openDeleteAlert(product)}
                          className="p-2 text-zinc-400 hover:text-red-400 hover:bg-red-500/10 rounded transition-colors"
                          title="Eliminar producto"
                        >
                          <Trash className="w-4 h-4" />
                        </button>
                      </div>
                    </TableCell>
                  </TableRow>
                ))}
              </TableBody>
            </Table>
          </div>
        )}
      </div>
    </div>
  )
}
